Hi, that's happening because you're actually overriding the `post` method of [BaseUpdateWithInlinesView](https://github.com/AndrewIngram/django-extra-views/blob/master/extra_views/advanced.py#L149) which sets `self.object`.  The code as you have written it will also create the Post object even if the inline data contains an error...are you sure you want to do that? I think the code below might be more straightforward, assuming `self.object.author` does not need to be set in order to validate the inlines:
```
class PostCreateView(CreateWithInlinesView):
    model = Post
    form_class = PostForm
    inlines = [PostFileFormSet]
    template_name = 'form_create.html'

    @method_decorator(login_required)
    def dispatch(self, *args, **kwargs):
        return super(PostCreateView, self).dispatch(*args, **kwargs)

    def get_success_url(self):
        return self.object.get_absolute_url()

    def forms_valid(self, form, inlines):
        """
        If the form and formsets are valid, save the associated models.
        """
        self.object = form.save(commit=False)
        self.object.author = self.request.user
        self.object.save()
        form.save_m2m()
        messages.success(self.request, 'Post was successfully created!')
        for formset in inlines:
            formset.save()
        return HttpResponseRedirect(self.get_success_url())

    def forms_invalid(self, form, inlines):
        """
        If the form or formsets are invalid, re-render the context data with the
        data-filled form and formsets and errors.
        """
        messages.error(self.request, 'Oooops! Please correct the error below and try again!')
        return self.render_to_response(self.get_context_data(form=form, inlines=inlines))
```

